/**
 * @file
 * Progress behavior.
 *
 * @see progress.js
 */

.progress {
  position: relative;
}
.progress__track {
  min-width: 100px;
  max-width: 100%;
  height: 16px;
  margin-top: 5px;
  border: 1px solid;
  background-color: #fff;
}
.progress__bar {
  width: 3%;
  min-width: 3%;
  max-width: 100%;
  height: 16px;
  background-color: #000;
}
.progress__description,
.progress__percentage {
  overflow: hidden;
  margin-top: 0.2em;
  color: #555;
  font-size: 0.875em;
}
.progress__description {
  float: left; /* LTR */
}
[dir="rtl"] .progress__description {
  float: right;
}
.progress__percentage {
  float: right; /* LTR */
}
[dir="rtl"] .progress__percentage {
  float: left;
}
.progress--small .progress__track {
  height: 7px;
}
.progress--small .progress__bar {
  height: 7px;
  background-size: 20px 20px;
}

window.euCookieComplianceLoadScripts = function(category) {
  const unverifiedScripts = drupalSettings.eu_cookie_compliance.unverified_scripts;
  const scriptList = [{"src":"https://www.googletagmanager.com/gtag/js","options":{"categoryWrap":false,"categoryName":"","loadByBehavior":false,"attachName":null}},{"src":"/modules/contrib/google_tag/js/gtag.ajax.js","options":{"categoryWrap":false,"categoryName":"","loadByBehavior":false,"attachName":null}},{"src":"/modules/contrib/google_tag/js/gtag.js","options":{"categoryWrap":false,"categoryName":"","loadByBehavior":false,"attachName":null}},{"src":"/modules/contrib/google_tag/js/gtm.js","options":{"categoryWrap":false,"categoryName":"","loadByBehavior":false,"attachName":null}}];
  scriptList.forEach(({src, options}) => {
    function createSnippet(src, options) {
      const tag = document.createElement("script");
      tag.src = decodeURI(src);
      if (options.loadByBehavior && options.attachName) {
        const intervalId = setInterval(() => {
          if (Drupal.behaviors[options.attachName]) {
            Drupal.behaviors[options.attachName].attach(document, drupalSettings);
            clearInterval(intervalId);
          }
        }, 100);
      }
      document.body.appendChild(tag);
    }

    if (!unverifiedScripts.includes(src)) {
      if (options.categoryWrap && options.categoryName === category) {
        createSnippet(src, options);
      } else if (!options.categoryWrap) {
        createSnippet(src, options);
      }
    }
  });
}

/**
 * @file
 * Throbber.
 */

.ajax-progress {
  display: inline-block;
  padding: 1px 5px 2px 5px;
}
[dir="rtl"] .ajax-progress {
  float: right;
}
.ajax-progress-throbber .throbber {
  display: inline;
  padding: 1px 5px 2px;
  background: transparent url(../../../../../misc/throbber-active.gif) no-repeat 0 center;
}
.ajax-progress-throbber .message {
  display: inline;
  padding: 1px 5px 2px;
}
tr .ajax-progress-throbber .throbber {
  margin: 0 2px;
}
.ajax-progress-bar {
  width: 16em;
}

/* Full screen throbber */
.ajax-progress-fullscreen {
  position: fixed;
  z-index: 1000;
  top: 48.5%;
  /* Can't do center:50% middle: 50%, so approximate it for a typical window size. */
  left: 49%; /* LTR */
  width: 24px;
  height: 24px;
  padding: 4px;
  opacity: 0.9;
  border-radius: 7px;
  background-color: #232323;
  background-image: url(../../../../../misc/loading-small.gif);
  background-repeat: no-repeat;
  background-position: center center;
}
[dir="rtl"] .ajax-progress-fullscreen {
  right: 49%;
  left: auto;
}

/**
 * @file
 * External links css file.
 */

span.ext {
  width: 10px;
  height: 10px;
  padding-right: 12px;
  text-decoration: none;
  background: url('../images/extlink_s.png') 2px center no-repeat;
}

span.mailto {
  width: 10px;
  height: 10px;
  padding-right: 12px;
  text-decoration: none;
  background: url('../images/extlink_s.png') -20px center no-repeat;
}

span.tel {
  width: 10px;
  height: 10px;
  padding-right: 12px;
  text-decoration: none;
  background: url('../images/extlink_s.png') -42px center no-repeat;
}

svg.ext {
  width: 14px;
  height: 14px;
  fill: #727272;
  font-weight: 900;
}

svg.mailto,
svg.tel {
  width: 14px;
  height: 14px;
  fill: #727272;
}

[data-extlink-placement='prepend'],
[data-extlink-placement='before'] {
  padding-right: 0.2rem;
}

[data-extlink-placement='append'],
[data-extlink-placement='after'] {
  padding-left: 0.2rem;
}

svg.ext path,
svg.mailto path,
svg.tel path {
  stroke: #727272;
  stroke-width: 3;
}

/* Hide the extra icons when printing. */
@media print {
  svg.ext,
  svg.mailto,
  svg.tel,
  span.ext,
  span.mailto,
  span.tel {
    display: none;
    padding: 0;
  }
}

/* Put some whitespace between the link and its Font Awesome suffix. */
.extlink i {
  padding-left: 0.2em;
}

.extlink-nobreak {
  white-space: nowrap;
}

.paragraph--unpublished {
  background-color: #fff4f4;
}

/**
 * @file
 * Parse inline JSON and initialize the drupalSettings global object.
 */

(function () {
  // Use direct child elements to harden against XSS exploits when CSP is on.
  const settingsElement = document.querySelector(
    'head > script[type="application/json"][data-drupal-selector="drupal-settings-json"], body > script[type="application/json"][data-drupal-selector="drupal-settings-json"]',
  );

  /**
   * Variable generated by Drupal with all the configuration created from PHP.
   *
   * @global
   *
   * @type {object}
   */
  window.drupalSettings = {};

  if (settingsElement !== null) {
    window.drupalSettings = JSON.parse(settingsElement.textContent);
  }
})();

